#include <tlhelp32.h>

// Function to enumerate and print process details using EnumProcessModulesEx
void list_processes() {
    HANDLE hModuleSnap = INVALID_HANDLE_VALUE;
    MODULEENTRY32 me32;

    // Take a snapshot of all modules in the specified process or in all processes.
    hModuleSnap = CreateToolhelp32Snapshot(TH32CS_SNAPMODULE | TH32CS_SNAPPROCESS, 0);

    if (hModuleSnap == INVALID_HANDLE_VALUE) {
        printf("CreateToolhelp32Snapshot failed with error %d\n", GetLastError());
        return;
    }

    // Set size to be large enough for returned data
    me32.dwSize = sizeof(MODULEENTRY32);

    // Retrieve information about the first module,
    // and exit if unsuccessful
    if (!Module32First(hModuleSnap, &me32)) {
        printf("Module32First failed with error %d\n", GetLastError());
        CloseHandle(hModuleSnap);
        return;
    }

    printf("PID\t\t: %d\n", GetCurrentProcessId());

    do {
        printf("Name:\t\t %s\n", me32.szModule);
        printf("Path:\t\t %s\n", me32.szExePath);
        printf("\n");
    } while (Module32Next(hModuleSnap, &me32));

    CloseHandle(hModuleSnap);
}

